import'dart:convert';import'dart:io';import'package:path_provider/path_provider.dart';import'../models/chat_message.dart';class ChatPersistenceService{static final ChatPersistenceService _instance=ChatPersistenceService._internal();factory ChatPersistenceService()=>_instance;ChatPersistenceService._internal();Future<File>get _localFile async{final directory=await getApplicationDocumentsDirectory();return File('${directory.path}/chat_history.json');}Future<List<ChatMessage>>loadMessages() async{try{final file=await _localFile;if(!await file.exists())return[];final contents=await file.readAsString();final List<dynamic>jsonList=jsonDecode(contents);return jsonList.map((json)=>ChatMessage.fromJson(json)).toList();}catch(e){print('Error loading messages: $e');return[];}}Future<void>saveMessages(List<ChatMessage>messages) async{try{final file=await _localFile;final jsonList=messages.map((m)=>m.toJson()).toList();await file.writeAsString(jsonEncode(jsonList));}catch(e){print('Error saving messages: $e');}}}
